INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('grid-QfqiwdfC_X:i-_TsKJnk5vq', 'Kat Holmes', 'Kat Holmes is Senior VP of Product Experience at Salesforce where she''s driving the future of CRM experiences. As the author of the best-selling book Mismatch: How Inclusion Shapes Design, Holmes works with multidisciplinary teams to set a foundation for why designing with excluded communities drives better solutions for everyone. Her work has been featured by NPR, BBC, Fast Company, Forbes, The Economist, and many more.
