INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('grid-G67gzV1wjN:i-r5TQqyXmnn', 'Just Work', 'We―all of us―consistently exclude, underestimate, and underutilize huge numbers of people in the workforce even as we include, overestimate, and promote others, often beyond their level of competence. Not only is this immoral and unjust, but it’s also bad for business. Just Work is the solution.', 'https://www.radicalcandor.com/the-book/', (SELECT id FROM categories WHERE slug='books'), 'book', NULL, 'https://www.radicalcandor.com/wp-content/uploads/2021/09/JustWork_HCupdated-400x700.png', 'coda', 'published') ON CONFLICT(coda_row_id) DO UPDATE SET title=excluded.title, description=excluded.description, url=excluded.url, category_id=excluded.category_id, type=excluded.type, author=excluded.author, image_url=excluded.image_url, updated_at=current_timestamp;
