INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-EJH9HL3G_y', 'Assumptions', 'Why do it? We do this because if we do not identify and address our implicit assumptions, we may make uninformed decisions about the project or product''s direction. The output of this exercise can be used to generate user research questions.
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-EXXGunhqRX', 'Business Model Canvas (Lean)', 'Why do it? To create a shared understanding of the project’s goals and provide a basis for validation. This method can be done for an existing business model to identify opportunities or for a future business model to get a holistic view of the potential solution.
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-wWo2tYxdoy', 'Consequence Framing', 'Why do it? —
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-EYQIsbHNwb', 'Diagramming a D&F', 'Why do it? Diagramming a D&F for the core team and stakeholders helps to:
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-jjm3tWznfA', 'Goals & Anti-Goals', 'Why do it? Goals help the team decide where to focus their time and efforts. By developing them hand-in-hand with stakeholders, we can align ourselves around shared goals and avoid any unnecessary or unwanted surprises down the road.
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-jv1wfC-M3L', 'Insight Prioritization', 'Why do it? Insight Prioritization helps us understand "what are the first set of problems that need solving?". It looks at insights—"aha!" moments where critical thinking results in a meaningful conclusion—in order to help provide color to our problem space and eventual solutions.
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-rM1YdwaVvC', 'Journey Map', 'Why do it? During Discovery, a journey map can help arrange individual data points into chronological order. During Framing, the team can return to a journey map to identify the point in the journey when a proposed solution will be used by a customer.
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-j6qOO2J2g0', 'Molecule Map', 'Why do it? Molecule maps help team members understand that there are multiple possible solutions to a user’s need, and that solutions are best understood alongside their relationship to these users and needs
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-lvZZ1RjuGF', 'MVP Canvas', 'Why do it? A company might choose to develop and release a minimum viable product because its product team wants to:
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-eZ5RgF4QNS', 'Risk Mitigations', 'Why do it? We do this to create a forum where people feel comfortable sharing fears and concerns in order to proactively mitigate issues we think may arise. This session results in a list of prioritized action items that the team can use to get ahead of any risks.
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-fld-KOpRUI', 'Road Map', 'Why do it? Long term or short term, road map helps the team to plan, visualize and share. It defines the goal and desired outcome. Visualize milestones, and contingency plans.
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-T4uioZJEh-', 'Scenario Writing', 'Why do it? This activity allows the team to tell a story about either the user''s current, potentially frustrating experience with the core problem or their future, ideally positive experience after the team’s solution is in place. Doing this provides structure in advance of exploratory research—drawing out areas to probe—or leverages what the team has learned to support solution sketching.
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-WtoyeYV_6y', 'Scoping for PRD', 'Why do it? - To hear from the stakeholder and understand the goals, needs and details of the project;
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-adXHdDQ6Tu', 'Stakeholder Map', 'Why do it? Sometimes projects involve large numbers of stakeholders in varying departments. Stakeholder maps are a tried-and-true method for driving out the specifics of who:
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-Yk_G7h7ouE', 'Value Proposition', 'Why do it? To identify and articulate product value. Looking at the business needs vs. customer segments. It help the product team to break the value proposition down into products and services, pain relievers, and gain creators.
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('method:grid-_0-iJXB6_V', 'Wardley Mapping Canvas', 'Why do it? Use mapping as a way to quickly validate solutions and avoid costly mistakes, to identify what to build, buy and outsource
