INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('grid-AzNPKXt0uZ:i-CfT3CLgs6C', 'Make your own map', 'I came across this book while taking a course in women leadership at Oxford. Kathryn Bishop is one of the instructors. This book helped me so much in term of thinking about how to map out personal strength. I use the two by two to talk about career growth, I use it to talk about how to interview answer the “weakness” question. I ran the activity to help teams and individuals to map out their strength and form a development plan. The world is not black and white, the thinking is not black and white, people are not 2 dimension.', 'https://kathryn-bishop.com/books/make-your-own-map/', (SELECT id FROM categories WHERE slug='self-leadership'), 'article', NULL, NULL, 'coda', 'published') ON CONFLICT(coda_row_id) DO UPDATE SET title=excluded.title, description=excluded.description, url=excluded.url, category_id=excluded.category_id, type=excluded.type, author=excluded.author, image_url=excluded.image_url, updated_at=current_timestamp;
