INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('page:canvas-fuh7kAS6EP', 'Baader-Meinhof Effect', 'The brain seeks things it is comfortable with and latches on to those, thus, ignoring other things it is not as familiar with. So, when a pattern or name rings true to us, our brain latches on to it. As a result, we tend to think we see or hear that item more than we actually do. In other words, in the Baader-Meinhof effect trends might NOT actually be as frequent as the person is stating. It might just be in their mind.', NULL, (SELECT id FROM categories WHERE slug='random-collection-wip'), 'note', NULL, NULL, 'coda', 'published') ON CONFLICT(coda_row_id) DO UPDATE SET title=excluded.title, description=excluded.description, url=excluded.url, category_id=excluded.category_id, type=excluded.type, author=excluded.author, image_url=excluded.image_url, updated_at=current_timestamp;
INSERT INTO resources (coda_row_id, title, description, url, category_id, type, author, image_url, source, status) VALUES ('page:canvas-i5srg5q0Lc', 'Framing Effect', 'Framing effect can be used for good or evil. What happens with the framing effect is people draw different conclusions from the same information, depending on how that information is presented.
